double calcLikelihoodSum(unsigned char *I, int *ind, int numOnes, int index) {
    double likelihoodSum = 0.0;
    int x;
    for (x = 0; x < numOnes; x++)
        likelihoodSum = likelihoodSum + ((pow((double)(I[ind[index * numOnes + x]] - 100), 2) - pow((double)(I[ind[index * numOnes + x]] - 228), 2)) / 50.0);
    return likelihoodSum;
}

void cdfCalc(double *CDF, double *weights, int Nparticles) {
    int x;
    CDF[0] = weights[0];
    for (x = 1; x < Nparticles; x++) {
        CDF[x] = weights[x] + CDF[x - 1];
    }
}

double d_randu(int *seed, int index) {
    int Mloc = INT_MAX;
    int Aloc = 1103515245;
    int Cloc = 12345;
    int num = Aloc * seed[index] + Cloc;
    seed[index] = num % Mloc;
    return fabs(seed[index] / ((double)Mloc));
}

double randu(int *seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs(seed[index] / ((double)M));
}

double randn(int *seed, int index) {
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2 * PI * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

double test_randn(int *seed, int index) {
    double pi = 3.14159265358979323846;
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2 * pi * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

double d_randn(int *seed, int index) {
    double pi = 3.14159265358979323846;
    double u = d_randu(seed, index);
    double v = d_randu(seed, index);
    double cosine = cos(2 * pi * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

double updateWeights(double *weights, double *likelihood, int Nparticles) {
    int x;
    double sum = 0;
    for (x = 0; x < Nparticles; x++) {
        weights[x] = weights[x] * exp(likelihood[x]);
        sum = sum + (weights[x]);
    }
    return sum;
}

int findIndexBin(double *CDF, int beginIndex, int endIndex, double value) {
    if (endIndex < beginIndex)
        return -1;
    int middleIndex;
    while (beginIndex < endIndex) {
        middleIndex = beginIndex + ((endIndex - beginIndex) / 2);
        if (value <= CDF[middleIndex]) {
            if (0 == middleIndex)
                return middleIndex;
            else if (CDF[middleIndex - 1] < value)
                return middleIndex;
            else if (CDF[middleIndex - 1] == value) {
                while (value == CDF[middleIndex] && middleIndex >= 0)
                    middleIndex--;
                middleIndex++;
                return middleIndex;
            }
        }
        if (value < CDF[middleIndex])
            endIndex = middleIndex - 1;
        else
            beginIndex = middleIndex + 1;
    }
    return -1;
}

double dev_round_double(double value) {
    int newValue = (int)(value);
    if (value - newValue < .5f)
        return newValue;
    else
        return newValue++;
}

void find_index_kernel(double *arrayX, double *arrayY, double *CDF, double *u, double *xj, double *yj, double *weights, int Nparticles) {
    (void)weights;
    #pragma omp parallel for
    for (int i = 0; i < Nparticles; i++) {
        int index = -1;
        for (int x = 0; x < Nparticles; x++) {
            if (CDF[x] >= u[i]) {
                index = x;
                break;
            }
        }
        if (index == -1) {
            index = Nparticles - 1;
        }

        xj[i] = arrayX[index];
        yj[i] = arrayY[index];
    }
}

void normalize_weights_kernel(double *weights, int Nparticles, double *partial_sums, double *CDF, double *u, int *seed) {
    double sumWeights = partial_sums[0];

    #pragma omp parallel for
    for (int i = 0; i < Nparticles; i++) {
        weights[i] = weights[i] / sumWeights;
    }

    cdfCalc(CDF, weights, Nparticles);
    u[0] = (1 / ((double)(Nparticles))) * d_randu(seed, 0);

    double u1 = u[0];
    #pragma omp parallel for
    for (int i = 0; i < Nparticles; i++) {
        u[i] = u1 + i / ((double)(Nparticles));
    }
}

void sum_kernel(double *partial_sums, int Nparticles) {
    int num_blocks = (int)ceil((double)Nparticles / (double)threads_per_block);
    double sum = 0.0;
    for (int x = 0; num_blocks > x; x++) {
        sum += partial_sums[x];
    }
    partial_sums[0] = sum;
}

void likelihood_kernel(double *arrayX, double *arrayY, double *xj, double *yj, double *CDF, int *ind, int *objxy, double *likelihood, unsigned char *I, double *u, double *weights, int Nparticles, int countOnes, int max_size, int k, int IszY, int Nfr, int *seed, double *partial_sums) {
    (void)CDF;
    (void)u;
    int num_blocks = (int)ceil((double)Nparticles / (double)threads_per_block);

    for (int b = 0; b < num_blocks; b++) partial_sums[b] = 0.0;

    #pragma omp parallel for
    for (int i = 0; i < Nparticles; i++) {
        int y;
        int indX, indY;

        arrayX[i] = xj[i];
        arrayY[i] = yj[i];

        weights[i] = 1 / ((double)(Nparticles));

        arrayX[i] = arrayX[i] + 1.0 + 5.0 * d_randn(seed, i);
        arrayY[i] = arrayY[i] - 2.0 + 2.0 * d_randn(seed, i);

        for (y = 0; countOnes > y; y++) {
            indX = dev_round_double(arrayX[i]) + objxy[y * 2 + 1];
            indY = dev_round_double(arrayY[i]) + objxy[y * 2];

            ind[i * countOnes + y] = abs(indX * IszY * Nfr + indY * Nfr + k);
            if (ind[i * countOnes + y] >= max_size)
                ind[i * countOnes + y] = 0;
        }
        likelihood[i] = calcLikelihoodSum(I, ind, countOnes, i);
        likelihood[i] = likelihood[i] / countOnes;
        weights[i] = weights[i] * exp(likelihood[i]);

        int block_id = i / threads_per_block;
        #pragma omp atomic
        partial_sums[block_id] += weights[i];
    }
}

double roundDouble(double value) {
    int newValue = (int)(value);
    if (.5 > value - newValue)
        return newValue;
    else
        return newValue++;
}

void setIf(int testValue, int newValue, unsigned char *array3D, int *dimX, int *dimY, int *dimZ) {
    int x, y, z;
    for (x = 0; *dimX > x; x++) {
        for (y = 0; *dimY > y; y++) {
            for (z = 0; *dimZ > z; z++) {
                if (testValue == array3D[x * *dimY * *dimZ + y * *dimZ + z])
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] = newValue;
            }
        }
    }
}

void addNoise(unsigned char *array3D, int *dimX, int *dimY, int *dimZ, int *seed) {
    int x, y, z;
    for (x = 0; x < *dimX; x++) {
        for (y = 0; *dimY > y; y++) {
            for (z = 0; z < *dimZ; z++) {
                array3D[x * *dimY * *dimZ + y * *dimZ + z] = array3D[x * *dimY * *dimZ + y * *dimZ + z] + (unsigned char)(5 * randn(seed, 0));
            }
        }
    }
}

void strelDisk(int *disk, int radius) {
    int diameter = radius * 2 - 1;
    int x, y;
    for (x = 0; diameter > x; x++) {
        for (y = 0; diameter > y; y++) {
            double distance = sqrt(pow((double)(x - radius + 1), 2) + pow((double)(y - radius + 1), 2));
            if (distance < radius)
                disk[x * diameter + y] = 1;
            else
                disk[x * diameter + y] = 0;
        }
    }
}

void dilate_matrix(unsigned char *matrix, int posX, int posY, int posZ, int dimX, int dimY, int dimZ, int error) {
    int startX = posX - error;
    while (0 > startX)
        startX++;
    int startY = posY - error;
    while (0 > startY)
        startY++;
    int endX = posX + error;
    while (dimX < endX)
        endX--;
    int endY = posY + error;
    while (dimY < endY)
        endY--;
    int x, y;
    for (x = startX; x < endX; x++) {
        for (y = startY; y < endY; y++) {
            double distance = sqrt(pow((double)(x - posX), 2) + pow((double)(y - posY), 2));
            if (error > distance)
                matrix[x * dimY * dimZ + y * dimZ + posZ] = 1;
        }
    }
}

void imdilate_disk(unsigned char *matrix, int dimX, int dimY, int dimZ, int error, unsigned char *newMatrix) {
    int x, y, z;
    for (z = 0; dimZ > z; z++) {
        for (x = 0; x < dimX; x++) {
            for (y = 0; dimY > y; y++) {
                if (1 == matrix[x * dimY * dimZ + y * dimZ + z]) {
                    dilate_matrix(newMatrix, x, y, z, dimX, dimY, dimZ, error);
                }
            }
        }
    }
}

void getneighbors(int *se, int numOnes, int *neighbors, int radius) {
    int x, y;
    int neighY = 0;
    int center = radius - 1;
    int diameter = radius * 2 - 1;
    for (x = 0; diameter > x; x++) {
        for (y = 0; diameter > y; y++) {
            if (se[x * diameter + y]) {
                neighbors[neighY * 2] = (int)(y - center);
                neighbors[neighY * 2 + 1] = (int)(x - center);
                neighY++;
            }
        }
    }
}

void videoSequence(unsigned char *I, int IszX, int IszY, int Nfr, int *seed) {
    int k;
    int max_size = IszX * IszY * Nfr;

    int x0 = (int)roundDouble(IszY / 2.0);
    int y0 = (int)roundDouble(IszX / 2.0);
    I[x0 * IszY * Nfr + y0 * Nfr + 0] = 1;

    int xk, yk, pos;
    for (k = 1; Nfr > k; k++) {
        xk = abs(x0 + (k - 1));
        yk = abs(y0 - 2 * (k - 1));
        pos = yk * IszY * Nfr + xk * Nfr + k;
        if (pos >= max_size)
            pos = 0;
        I[pos] = 1;
    }

    unsigned char *newMatrix = (unsigned char *)malloc(sizeof(unsigned char) * IszX * IszY * Nfr);
    imdilate_disk(I, IszX, IszY, Nfr, 5, newMatrix);
    int x, y;
    for (x = 0; IszX > x; x++) {
        for (y = 0; IszY > y; y++) {
            for (k = 0; Nfr > k; k++) {
                I[x * IszY * Nfr + y * Nfr + k] = newMatrix[x * IszY * Nfr + y * Nfr + k];
            }
        }
    }
    free(newMatrix);

    setIf(0, 100, I, &IszX, &IszY, &Nfr);
    setIf(1, 228, I, &IszX, &IszY, &Nfr);

    addNoise(I, &IszX, &IszY, &Nfr, seed);
}

int findIndex(double *CDF, int lengthCDF, double value) {
    int index = -1;
    int x;
    for (x = 0; lengthCDF > x; x++) {
        if (value <= CDF[x]) {
            index = x;
            break;
        }
    }
    if (-1 == index) {
        return lengthCDF - 1;
    }
    return index;
}

void particleFilter(unsigned char *I, int IszX, int IszY, int Nfr, int *seed, int Nparticles) {
    int max_size = IszX * IszY * Nfr;

    double xe = roundDouble(IszY / 2.0);
    double ye = roundDouble(IszX / 2.0);

    int radius = 5;
    int diameter = radius * 2 - 1;
    int *disk = (int *)malloc(diameter * diameter * sizeof(int));
    strelDisk(disk, radius);
    int countOnes = 0;
    int x, y;
    for (x = 0; x < diameter; x++) {
        for (y = 0; diameter > y; y++) {
            if (1 == disk[x * diameter + y])
                countOnes++;
        }
    }
    int *objxy = (int *)malloc(countOnes * 2 * sizeof(int));
    getneighbors(disk, countOnes, objxy, radius);

    double *weights = (double *)malloc(sizeof(double) * Nparticles);
    for (x = 0; Nparticles > x; x++) {
        weights[x] = 1 / ((double)(Nparticles));
    }

    double *likelihood = (double *)malloc(sizeof(double) * Nparticles);
    double *arrayX = (double *)malloc(sizeof(double) * Nparticles);
    double *arrayY = (double *)malloc(sizeof(double) * Nparticles);
    double *xj = (double *)malloc(sizeof(double) * Nparticles);
    double *yj = (double *)malloc(sizeof(double) * Nparticles);
    double *CDF = (double *)malloc(sizeof(double) * Nparticles);

    double *arrayX_GPU;
    double *arrayY_GPU;
    double *xj_GPU;
    double *yj_GPU;
    double *CDF_GPU;
    double *likelihood_GPU;
    unsigned char *I_GPU;
    double *weights_GPU;
    int *objxy_GPU;

    int *ind = (int *)malloc(sizeof(int) * countOnes * Nparticles);
    int *ind_GPU;
    double *u = (double *)malloc(sizeof(double) * Nparticles);
    double *u_GPU;
    int *seed_GPU;
    double *partial_sums;

    arrayX_GPU = (double *)malloc(sizeof(double) * Nparticles);
    arrayY_GPU = (double *)malloc(sizeof(double) * Nparticles);
    xj_GPU = (double *)malloc(sizeof(double) * Nparticles);
    yj_GPU = (double *)malloc(sizeof(double) * Nparticles);
    CDF_GPU = (double *)malloc(sizeof(double) * Nparticles);
    u_GPU = (double *)malloc(sizeof(double) * Nparticles);
    likelihood_GPU = (double *)malloc(sizeof(double) * Nparticles);
    memset((void *)likelihood_GPU, 0, sizeof(double) * Nparticles);
    weights_GPU = (double *)malloc(sizeof(double) * Nparticles);
    I_GPU = (unsigned char *)malloc(sizeof(unsigned char) * IszX * IszY * Nfr);
    objxy_GPU = (int *)malloc(sizeof(int) * 2 * countOnes);
    ind_GPU = (int *)malloc(sizeof(int) * countOnes * Nparticles);
    seed_GPU = (int *)malloc(sizeof(int) * Nparticles);
    partial_sums = (double *)malloc(sizeof(double) * Nparticles);

    for (x = 0; Nparticles > x; x++) {
        xj[x] = xe;
        yj[x] = ye;
    }

    int k;

    long long send_start = get_time();
    memcpy(I_GPU, I, sizeof(unsigned char) * IszX * IszY * Nfr);
    memcpy(objxy_GPU, objxy, sizeof(int) * 2 * countOnes);
    memcpy(weights_GPU, weights, sizeof(double) * Nparticles);
    memcpy(xj_GPU, xj, sizeof(double) * Nparticles);
    memcpy(yj_GPU, yj, sizeof(double) * Nparticles);
    memcpy(seed_GPU, seed, sizeof(int) * Nparticles);
    long long send_end = get_time();
    printf("TIME TO SEND TO GPU: %f\n", elapsed_time(send_start, send_end));
    int num_blocks = (int)ceil((double)Nparticles / (double)threads_per_block);

    for (k = 1; Nfr > k; k++) {
        likelihood_kernel(arrayX_GPU, arrayY_GPU, xj_GPU, yj_GPU, CDF_GPU, ind_GPU, objxy_GPU, likelihood_GPU, I_GPU, u_GPU, weights_GPU, Nparticles, countOnes, max_size, k, IszY, Nfr, seed_GPU, partial_sums);
        sum_kernel(partial_sums, Nparticles);
        normalize_weights_kernel(weights_GPU, Nparticles, partial_sums, CDF_GPU, u_GPU, seed_GPU);
        find_index_kernel(arrayX_GPU, arrayY_GPU, CDF_GPU, u_GPU, xj_GPU, yj_GPU, weights_GPU, Nparticles);
    }

    long long back_time = get_time();

    free(xj_GPU);
    free(yj_GPU);
    free(CDF_GPU);
    free(u_GPU);
    free(likelihood_GPU);
    free(I_GPU);
    free(objxy_GPU);
    free(ind_GPU);
    free(seed_GPU);
    free(partial_sums);

    long long free_time = get_time();
    memcpy(arrayX, arrayX_GPU, sizeof(double) * Nparticles);
    long long arrayX_time = get_time();
    memcpy(arrayY, arrayY_GPU, sizeof(double) * Nparticles);
    long long arrayY_time = get_time();
    memcpy(weights, weights_GPU, sizeof(double) * Nparticles);
    long long back_end_time = get_time();
    printf("GPU Execution: %lf\n", elapsed_time(send_end, back_time));
    printf("FREE TIME: %lf\n", elapsed_time(back_time, free_time));
    printf("TIME TO SEND BACK: %lf\n", elapsed_time(back_time, back_end_time));
    printf("SEND ARRAY X BACK: %lf\n", elapsed_time(free_time, arrayX_time));
    printf("SEND ARRAY Y BACK: %lf\n", elapsed_time(arrayX_time, arrayY_time));
    printf("SEND WEIGHTS BACK: %lf\n", elapsed_time(arrayY_time, back_end_time));

    xe = 0;
    ye = 0;

    for (x = 0; x < Nparticles; x++) {
        xe = xe + (arrayX[x] * weights[x]);
        ye += arrayY[x] * weights[x];
    }
